  ('pukao-e9ff7ca9-moex-00247', 'pukao-e9ff7ca9', 'pukao-e9ff7ca9-moex-112-4dccc0e6', 'sub-pukao-e9ff7ca9-01', NULL, 'single_choice', '「讓風險利益相關者瞭解所面對的風險，並參與決策，進而瞭解風險管理的作用，在風險管理的過程中取 得信任」。這段敘述在說明下列何種概念？', '["風險評估", "風險轉移", "風險規避", "風險溝通"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:28+00:00", "source_pdf_sha1": "64bf518f70b8", "answer_pdf_sha1": "7ce0a260f6de", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "403", "s": "0302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政學概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "客家事務行政"}'::jsonb, NULL),
